module mux_2to1(
    input in0,          // 1-bit input.
    input in1,          // 1-bit input.
    input sel,          // 1-bit select signal.
    input en,           // Enable signal to activate the multiplexer.

    output out          // 1-bit output.
);

reg unused_out_r;

//------------------------------------------------
// Multiplexer logic
always @(*) begin
    if (en) begin
        case (sel)
            1'b0: unused_out_r = in0;
            1'b1: unused_out_r = in1;
            default: unused_out_r = 1'b0;
        endcase
    end else begin
        unused_out_r = 1'b0;
    end
end

assign out = unused_out_r;

endmodule
